import argparse
from kafka import AdminClient
from kafka.structs import TopicPartition

def parse_args():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap_servers', required=True, help='List of Kafka bootstrap servers (e.g., localhost:9092)')
    parser.add_argument('--topic_name', required=True, help='Topic name to create or manage')
    parser.add_argument('--num_partitions', type=int, default=1, help='Number of partitions for the topic')
    parser.add_argument('--replication_factor', type=int, default=1, help='Replication factor for the topic')
    parser.add_argument('--config', nargs='+', help='Topic configuration (e.g., retention.ms, min.isr.replicas)')
    return parser.parse_args()

def create_topic(admin_client, topic_name, num_partitions, replication_factor):
    try:
        admin_client.create_topics(new_topics=[(topic_name, {'num.partitions': num_partitions, 'replication.factor': replication_factor})])
        print(f'Topic {topic_name} created successfully')
    except Exception as e:
        print(f'Error creating topic: {e}')

def manage_partitions(admin_client, topic_name):
    try:
        partitions = admin_client.list_topics().topics[topic_name]
        for partition in partitions.partitions:
            if partition.replicas != [partition.leader]:
                print(f'Reconfiguring partition {partition.partition} of topic {topic_name}')
                admin_client.alter_topic_partitions(new_partition_assignment={topic_name: [(partition.partition, partition.leader)]})
    except Exception as e:
        print(f'Error managing partitions: {e}')

def configure_topic(admin_client, topic_name, config):
    try:
        for key, value in config.items():
            admin_client.alter_topics([{'name': topic_name, 'configs': [{'config.name': key, 'config.value': value}]}])
            print(f'Topic configuration updated successfully: {key} = {value}')
    except Exception as e:
        print(f'Error configuring topic: {e}')

def main():
    args = parse_args()
    
    admin_client = AdminClient({'bootstrap.servers': args.bootstrap_servers})
    
    if args.config is not None:
        configure_topic(admin_client, args.topic_name, dict(zip(args.config[::2], args.config[1::2])))
    else:
        create_topic(admin_client, args.topic_name, args.num_partitions, args.replication_factor)
        manage_partitions(admin_client, args.topic_name)

if __name__ == '__main__':
    main()